// ═══════════════════════════════════════════════════
// EXTRACT EMAIL METADATA FROM INDEED
// ═══════════════════════════════════════════════════
const items = $input.all();
const output = [];

for (const item of items) {
  const subject = item.json.subject || '';
  const from = item.json.from || '';
  const date = item.json.date || new Date().toISOString();

  // Regex on Indeed subject: "New application for X - Y"
  // ⚠️ Adapt this regex to match your Indeed email language/format
  const positionMatch = subject.match(/per\s+(.+?)\s+-/i);
  const candidateMatch = subject.match(/-\s*(.+)$/);

  const position = positionMatch ? positionMatch[1].trim() : 'Unknown position';
  const candidateName = candidateMatch ? candidateMatch[1].trim() : 'Unknown candidate';

  // Filter valid attachments (PDF/DOCX only)
  const attachments = item.binary || {};
  const attachmentKeys = Object.keys(attachments).filter(k => {
    const mime = attachments[k].mimeType || '';
    return mime.includes('pdf') || mime.includes('word') || mime.includes('document');
  });

  if (attachmentKeys.length === 0) {
    continue; // Skip emails without a CV attachment
  }

  for (const key of attachmentKeys) {
    const executionStart = Date.now();
    output.push({
      json: {
        _meta: { executionStart },
        subject,
        from,
        date,
        position,
        candidateName,
        attachmentKey: key,
        fileName: attachments[key].fileName || `cv_${Date.now()}.pdf`,
        mimeType: attachments[key].mimeType
      },
      binary: {
        cv: attachments[key]
      }
    });
  }
}

return output;

