// ═══════════════════════════════════════════════════
// VALIDATE & ENRICH + BUILD EMAIL HTML
// ═══════════════════════════════════════════════════
const items = $input.all();
const output = [];

for (const item of items) {
  let parsed = item.json.output || item.json;

  // Safety net: handle string responses
  if (typeof parsed === 'string') {
    try {
      parsed = JSON.parse(parsed.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim());
    } catch (err) {
      output.push({
        json: {
          error: true,
          errorMessage: 'Parse error: ' + err.message,
          rawResponse: item.json
        }
      });
      continue;
    }
  }

  // Validate required fields
  const requiredFields = ['nome', 'cognome', 'posizione', 'punteggio', 'raccomandazione'];
  const missing = requiredFields.filter(f => !(f in parsed));
  if (missing.length > 0) {
    output.push({
      json: {
        error: true,
        errorMessage: 'Missing fields: ' + missing.join(', '),
        partialData: parsed
      }
    });
    continue;
  }

  // Retrieve upstream context
  const ctx = $node['🧹 Clean Text'].json;
  const meta = ctx._meta || {};

  // Clamp score to [0, 100]
  parsed.punteggio = Math.max(0, Math.min(100, Number(parsed.punteggio) || 0));
  const score = parsed.punteggio;

  // Force score <-> recommendation consistency
  const expectedRec = score <= 30 ? 'REJECT'
    : score <= 60 ? 'REVIEW'
    : score <= 80 ? 'INTERVIEW'
    : 'STRONG_HIRE';
  const recCorrected = parsed.raccomandazione !== expectedRec;
  if (recCorrected) {
    parsed.raccomandazione_originale = parsed.raccomandazione;
    parsed.raccomandazione = expectedRec;
  }

  // Execution time
  const executionTime = meta.executionStart ? ((Date.now() - meta.executionStart) / 1000).toFixed(1) : 'N/A';

  // Score badge color
  const scoreColor = score >= 81 ? '#22c55e'
    : score >= 61 ? '#3b82f6'
    : score >= 31 ? '#f59e0b'
    : '#ef4444';

  // Build HTML email
  const puntiForza = (parsed.punti_forza || []).map(p => `<li>${p}</li>`).join('');
  const puntiDebolezza = (parsed.punti_debolezza || []).map(p => `<li>${p}</li>`).join('');
  const competenze = (parsed.competenze_chiave || []).map(c => `<span style="display:inline-block;background:#e0e7ff;color:#3730a3;padding:3px 10px;border-radius:12px;margin:2px;font-size:12px">${c}</span>`).join(' ');
  const lingue = (parsed.lingue || []).join(' · ');

  const emailHtml = `
<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:680px;margin:0 auto;color:#1f2937">
  <div style="background:linear-gradient(135deg,${scoreColor} 0%,${scoreColor}dd 100%);color:white;padding:24px;border-radius:12px 12px 0 0">
    <div style="font-size:11px;opacity:0.85;letter-spacing:1.5px;text-transform:uppercase">🎯 New top candidate</div>
    <div style="font-size:24px;font-weight:600;margin-top:8px">${parsed.nome} ${parsed.cognome}</div>
    <div style="opacity:0.9;margin-top:4px">${parsed.posizione}</div>
  </div>

  <div style="background:white;border:1px solid #e5e7eb;border-top:0;border-radius:0 0 12px 12px;padding:24px">

    <div style="display:flex;gap:16px;margin-bottom:24px;flex-wrap:wrap">
      <div style="flex:1;min-width:140px;background:#f9fafb;padding:16px;border-radius:8px;text-align:center">
        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:1px">Score</div>
        <div style="font-size:36px;font-weight:700;color:${scoreColor};margin-top:4px">${score}<span style="font-size:18px;color:#9ca3af">/100</span></div>
      </div>
      <div style="flex:1;min-width:140px;background:#f9fafb;padding:16px;border-radius:8px;text-align:center">
        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:1px">Recommendation</div>
        <div style="font-size:18px;font-weight:600;color:${scoreColor};margin-top:8px">${parsed.raccomandazione}</div>
      </div>
      <div style="flex:1;min-width:140px;background:#f9fafb;padding:16px;border-radius:8px;text-align:center">
        <div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:1px">Years of experience</div>
        <div style="font-size:18px;font-weight:600;color:#374151;margin-top:8px">${parsed.anni_esperienza || 'N/A'}</div>
      </div>
    </div>

    <div style="background:#f3f4f6;padding:14px 16px;border-radius:8px;margin-bottom:20px;font-size:14px;color:#4b5563;border-left:3px solid ${scoreColor}">
      <strong style="color:#1f2937">Summary:</strong> ${parsed.spiegazione_breve}
    </div>

    <h3 style="font-size:14px;color:#374151;margin:20px 0 8px;text-transform:uppercase;letter-spacing:1px">📋 Profile</h3>
    <table style="width:100%;font-size:14px;color:#4b5563;border-collapse:collapse">
      <tr><td style="padding:6px 0;width:140px;color:#6b7280">Email</td><td>${parsed.email || 'N/A'}</td></tr>
      <tr><td style="padding:6px 0;color:#6b7280">Phone</td><td>${parsed.telefono || 'N/A'}</td></tr>
      <tr><td style="padding:6px 0;color:#6b7280">Education</td><td>${parsed.titolo_studio || 'N/A'}</td></tr>
      <tr><td style="padding:6px 0;color:#6b7280">Languages</td><td>${lingue || 'N/A'}</td></tr>
    </table>

    <h3 style="font-size:14px;color:#374151;margin:20px 0 8px;text-transform:uppercase;letter-spacing:1px">🛠 Key Skills</h3>
    <div>${competenze}</div>

    <div style="display:flex;gap:16px;margin-top:20px;flex-wrap:wrap">
      <div style="flex:1;min-width:240px">
        <h3 style="font-size:14px;color:#15803d;margin:0 0 8px;text-transform:uppercase;letter-spacing:1px">✓ Strengths</h3>
        <ul style="margin:0;padding-left:20px;color:#374151;font-size:14px;line-height:1.6">${puntiForza}</ul>
      </div>
      <div style="flex:1;min-width:240px">
        <h3 style="font-size:14px;color:#b91c1c;margin:0 0 8px;text-transform:uppercase;letter-spacing:1px">⚠ Weaknesses</h3>
        <ul style="margin:0;padding-left:20px;color:#374151;font-size:14px;line-height:1.6">${puntiDebolezza}</ul>
      </div>
    </div>

    <h3 style="font-size:14px;color:#374151;margin:24px 0 8px;text-transform:uppercase;letter-spacing:1px">📝 Detailed Analysis</h3>
    <div style="font-size:14px;color:#4b5563;line-height:1.7;background:#fafafa;padding:16px;border-radius:8px">${parsed.spiegazione_dettagliata}</div>

    ${recCorrected ? `<div style="margin-top:16px;background:#fef3c7;border-left:3px solid #f59e0b;padding:10px 14px;font-size:13px;color:#92400e;border-radius:4px">⚠️ Recommendation auto-corrected from "${parsed.raccomandazione_originale}" a "${parsed.raccomandazione}" per coerenza con il punteggio.</div>` : ''}

    <div style="margin-top:24px;padding-top:20px;border-top:1px solid #e5e7eb;display:flex;gap:24px;flex-wrap:wrap;font-size:12px;color:#9ca3af">
      <div>⏱ ${executionTime}s</div>
      <div>📄 <a href="${ctx.driveLink}" style="color:#3b82f6;text-decoration:none">Open CV on Drive</a></div>
      <div>🤖 Llama 3.3 70B (Groq)</div>
    </div>
  </div>
</div>
  `;

  output.push({
    json: {
      ...parsed,
      _emailHtml: emailHtml,
      _emailSubject: `🎯 ${parsed.nome} ${parsed.cognome} - Score ${score}/100 (${parsed.raccomandazione})`,
      cv_drive_link: ctx.driveLink,
      cv_filename: ctx.fileName,
      processed_at: new Date().toISOString(),
      execution_time: executionTime,
      error: false
    }
  });
}

return output;

// ═══════════════════════════════════════════════════
// CLEAN & NORMALIZE OCR OUTPUT
// ═══════════════════════════════════════════════════
const items = $input.all();
const output = [];

for (const item of items) {
  const ocrResponse = item.json;
  let fullText = '';

  if (ocrResponse.pages && Array.isArray(ocrResponse.pages)) {
    fullText = ocrResponse.pages
      .map(p => p.markdown || p.text || '')
      .join('\n\n');
  }

  // Normalize whitespace and newlines
  fullText = fullText
    .replace(/\s{3,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  // Retrieve context from previous nodes (production workflow)
  const meta = $('Extract Email Metadata').first().json;
  const drive = $('📁 Upload Drive').first().json;

  output.push({
    json: {
      _meta: meta._meta,
      cvText: fullText,
      candidateName: meta.candidateName,
      position: meta.position,
      applicationDate: meta.date,
      fileName: meta.fileName,
      driveLink: drive.webViewLink,
      driveId: drive.id,
      textLength: fullText.length
    }
  });
}

// Drop binary data to keep the flow lightweight
return output.map(item => ({ json: item.json }));
